response:
I have everything. The diagnosis is complete and unambiguous. Here is the full engineering response.

---

## Diagnosis

The portaled active label is landing to the **right** of the notch because the `left` inline style fed to `.highlightLabelAnchor` is set to `notch.getBoundingClientRect().left`, but the SCSS `transform: translate(calc(-100% - var(--portfolio-spacer-1x)), -50%)` **cannot reliably resolve its `-100%` X component** when the element is GPU-composited.

Here's the precise failure chain:

**In-rail hover labels** use this SCSS:
```scss
.label {
  position: absolute;
  right: calc(100% + var(--portfolio-spacer-1x));  /* right edge at: notch.left − 8px */
}
```
`100%` resolves against the **notch container's own width** (28px) at layout time — completely stable. ✅

**The portaled anchor** uses:
```scss
.highlightLabelAnchor {
  position: fixed;
  transform: translate(calc(-100% - var(--portfolio-spacer-1x)), -50%);
  will-change: top, left;   /* ← this is the trigger */
}
```
`will-change: top, left` causes the browser to **promote the anchor to its own compositor layer** before the inner `<motion.span>` text content is painted. At promotion time, the anchor's intrinsic width is **0** (the GPU layer is allocated before the text renders into it). `-100%` therefore resolves to `0px`, and `calc(0px - 8px)` = `-8px`. The full transform becomes `translate(-8px, -50%)` — a tiny leftward nudge instead of `-(labelWidth + 8px)`. The anchor's **right edge** lands at `notch.left - 8px + labelWidth`, which is **to the right** of the notch for any label wider than 0px. Longer labels clip past the viewport edge. This matches your symptom exactly.

Switching the measurement target from the tick element to the notch element was the right diagnosis (it fixes the `left` coordinate), but `will-change` makes the `transform` still wrong regardless of which element is measured. That's why you saw no visible change.

**Root cause: AP-070** (framer-motion / CSS transform composition) adjacent issue — `will-change: top, left` on a `position: fixed` element triggers early GPU layer promotion, which collapses `transform: translate(-100%, …)` to zero because the element has no width at promotion time. The fix is to **resolve the X offset in JavaScript** and bake it into the `left` value directly, leaving only `translateY(-50%)` in CSS (where `-50%` resolves against the known element height, not width — it's stable).

---

## Fix

Two files change. The JS takes over horizontal placement; the SCSS drops the X component.

### `src/components/ui/ScrollSpy/ScrollSpy.tsx`

Three changes:
1. Add `anchorRef` to measure the label's rendered width.
2. In `compute()`, read `anchorRef.current?.offsetWidth` and subtract it plus the spacer from `notch.left` — giving the final resolved `left` position.
3. Pass `anchorRef` to the anchor `div`.

```tsx
"use client";

import {
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
  useCallback,
} from "react";
import { createPortal } from "react-dom";
import { motion, AnimatePresence } from "framer-motion";
import { DURATION, EASING } from "@/lib/motion";
import styles from "./ScrollSpy.module.scss";

const useIsomorphicLayoutEffect =
  typeof window !== "undefined" ? useLayoutEffect : useEffect;

export type ScrollSpySection = {
  id: string;
  label: string;
  depth?: 0 | 1;
  group?: string;
};

type ScrollSpyProps = {
  sections: ScrollSpySection[];
};

// 1 design-system spacer unit = 8px. Matches --portfolio-spacer-1x.
const SPACER_1X = 8;

export default function ScrollSpy({ sections }: ScrollSpyProps) {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isHovered, setIsHovered] = useState(false);
  const [dragIndex, setDragIndex] = useState<number | null>(null);
  const [mounted, setMounted] = useState(false);
  const [overlayPos, setOverlayPos] = useState<{
    top: number;
    left: number;
  } | null>(null);

  const trackRef = useRef<HTMLDivElement>(null);
  // ─── NEW: ref to the portaled anchor so we can read its rendered width ───
  const anchorRef = useRef<HTMLDivElement>(null);
  // ─────────────────────────────────────────────────────────────────────────
  const drag = useRef({ active: false, index: -1 });
  const pointerStart = useRef<{ y: number; index: number } | null>(null);

  useEffect(() => setMounted(true), []);

  useEffect(() => {
    const elements = sections
      .map((s) => document.getElementById(s.id))
      .filter(Boolean) as HTMLElement[];

    if (elements.length === 0) return;

    const observer = new IntersectionObserver(
      (entries) => {
        if (drag.current.active) return;

        let best: IntersectionObserverEntry | null = null;
        for (const entry of entries) {
          if (!entry.isIntersecting) continue;
          if (
            !best ||
            entry.boundingClientRect.top < best.boundingClientRect.top
          ) {
            best = entry;
          }
        }

        if (best) {
          const idx = elements.indexOf(best.target as HTMLElement);
          if (idx !== -1) setActiveIndex(idx);
        }
      },
      { rootMargin: "-20% 0px -60% 0px", threshold: 0 },
    );

    elements.forEach((el) => observer.observe(el));
    return () => observer.disconnect();
  }, [sections]);

  const scrollTo = useCallback(
    (index: number, behavior: ScrollBehavior = "smooth") => {
      const el = document.getElementById(sections[index]?.id);
      if (el) {
        const top =
          el.getBoundingClientRect().top +
          window.scrollY -
          window.innerHeight * 0.2;
        window.scrollTo({ top: Math.max(0, top), behavior });
        setActiveIndex(index);
      }
    },
    [sections],
  );

  const indexFromPointer = useCallback((clientY: number): number => {
    const notches =
      trackRef.current?.querySelectorAll<HTMLElement>("[data-notch-index]");
    if (!notches || notches.length === 0) return 0;
    let closest = 0;
    let minDist = Infinity;
    notches.forEach((el, i) => {
      const rect = el.getBoundingClientRect();
      const dist = Math.abs(clientY - (rect.top + rect.height / 2));
      if (dist < minDist) {
        minDist = dist;
        closest = i;
      }
    });
    return closest;
  }, []);

  const onPointerDown = useCallback(
    (e: React.PointerEvent) => {
      if (e.button !== 0) return;
      e.preventDefault();
      trackRef.current?.setPointerCapture(e.pointerId);
      const idx = indexFromPointer(e.clientY);
      pointerStart.current = { y: e.clientY, index: idx };
    },
    [indexFromPointer],
  );

  const onPointerMove = useCallback(
    (e: React.PointerEvent) => {
      if (!pointerStart.current) return;

      if (!drag.current.active) {
        if (Math.abs(e.clientY - pointerStart.current.y) < 3) return;
        drag.current = { active: true, index: pointerStart.current.index };
        setDragIndex(pointerStart.current.index);
        scrollTo(pointerStart.current.index, "instant");
      }

      const idx = indexFromPointer(e.clientY);
      if (idx !== drag.current.index) {
        drag.current.index = idx;
        setDragIndex(idx);
        scrollTo(idx, "instant");
      }
    },
    [indexFromPointer, scrollTo],
  );

  const endInteraction = useCallback(() => {
    if (pointerStart.current && !drag.current.active) {
      scrollTo(pointerStart.current.index, "smooth");
    }
    drag.current = { active: false, index: -1 };
    pointerStart.current = null;
    setDragIndex(null);
  }, [scrollTo]);

  const isDragging = dragIndex !== null;
  const highlightIndex = isDragging ? dragIndex : activeIndex;
  const highlightVisible = isDragging ? dragIndex !== null : isHovered;
  const highlightSection =
    highlightIndex != null ? sections[highlightIndex] : undefined;
  const highlightDepth = highlightSection?.depth ?? 0;

  useIsomorphicLayoutEffect(() => {
    if (!mounted || !highlightVisible || highlightIndex == null) {
      setOverlayPos(null);
      return;
    }

    const compute = () => {
      const notch = trackRef.current?.querySelector<HTMLElement>(
        `[data-notch-index="${highlightIndex}"]`,
      );
      if (!notch) {
        setOverlayPos(null);
        return;
      }

      const r = notch.getBoundingClientRect();

      // ─── FIXED: resolve the X offset in JS, not in CSS ──────────────────
      // The CSS `.highlightLabelAnchor` previously used
      //   transform: translate(calc(-100% - spacer-1x), -50%)
      // intending -100% to equal -(label text width). But `will-change: top,
      // left` promotes the anchor to a GPU layer before the child text
      // renders, so -100% resolves against a 0-width box → the label lands
      // at notch.left - 8px + labelWidth (rightward, clipping past viewport).
      //
      // Fix: read anchorRef.current.offsetWidth here (after the text has
      // been painted into the anchor on a previous frame) and subtract it
      // plus the 1x spacer from notch.left. The CSS transform retains only
      // translateY(-50%) whose -50% is always stable (resolves against the
      // known line-height). This matches the in-rail .label positioning:
      //   right: calc(100% + spacer-1x)  →  right edge at notch.left - 8px
      // so the active label joins the same right-aligned gutter. See FB-156.
      // ────────────────────────────────────────────────────────────────────
      const labelWidth = anchorRef.current?.offsetWidth ?? 0;
      setOverlayPos({
        top: r.top + r.height / 2,
        left: r.left - labelWidth - SPACER_1X,
      });
    };

    compute();
    window.addEventListener("resize", compute);
    window.addEventListener("scroll", compute, true);
    return () => {
      window.removeEventListener("resize", compute);
      window.removeEventListener("scroll", compute, true);
    };
  }, [mounted, highlightVisible, highlightIndex]);

  if (sections.length < 2) return null;

  return (
    <>
      <nav className={styles.rail} aria-label="Page sections">
        <div
          ref={trackRef}
          className={styles.track}
          data-hovered={isHovered || undefined}
          data-dragging={isDragging || undefined}
          onPointerEnter={() => setIsHovered(true)}
          onPointerLeave={() => setIsHovered(false)}
          onPointerDown={onPointerDown}
          onPointerMove={onPointerMove}
          onPointerUp={endInteraction}
          onLostPointerCapture={endInteraction}
        >
          {sections.map((section, i) => {
            const isActive = i === activeIndex;
            const isDragTarget = isDragging && i === dragIndex;
            const showLabel = isDragging ? isDragTarget : isHovered;
            const isHighlight = i === highlightIndex;
            const depth = section.depth ?? 0;

            return (
              <div
                key={section.id}
                className={styles.notch}
                data-notch-index={i}
                data-active={isActive || undefined}
                data-depth={depth || undefined}
              >
                <AnimatePresence>
                  {showLabel && !isHighlight && (
                    <motion.span
                      className={styles.label}
                      initial={{ opacity: 0, x: 4 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: 4 }}
                      transition={{
                        duration: isDragging ? 0 : DURATION.fast,
                        ease: EASING.standard,
                      }}
                    >
                      {section.label}
                    </motion.span>
                  )}
                </AnimatePresence>

                <button
                  className={styles.tick}
                  data-active={isActive || undefined}
                  data-drag-target={isDragTarget || undefined}
                  data-depth={depth || undefined}
                  onClick={() => scrollTo(i)}
                  aria-label={`Jump to ${section.label}`}
                  aria-current={isActive ? "true" : undefined}
                />
              </div>
            );
          })}
        </div>
      </nav>

      {mounted &&
        highlightSection &&
        createPortal(
          // Two-element structure (AP-070 compliance): the anchor div owns
          // position and Y-centering; the inner motion.span owns only the
          // x/opacity slide-in so framer-motion's inline transform never
          // touches the anchor's placement.
          //
          // X placement is now fully resolved in JS (see compute() above).
          // The anchor's `left` = notch.left - labelWidth - 8px, so
          // its right edge lands at exactly notch.left - 8px — the same
          // gutter used by in-rail .label elements. See FB-156.
          <div
            ref={anchorRef}
            className={styles.highlightLabelAnchor}
            style={
              overlayPos
                ? {
                    top: `${overlayPos.top}px`,
                    left: `${overlayPos.left}px`,
                  }
                : { top: 0, left: 0, visibility: "hidden" }
            }
            aria-hidden="true"
          >
            <motion.span
              className={styles.highlightLabel}
              data-depth={highlightDepth || undefined}
              initial={false}
              animate={{
                opacity: highlightVisible && overlayPos ? 1 : 0,
                x: highlightVisible && overlayPos ? 0 : 4,
              }}
              transition={{
                duration: isDragging ? 0 : DURATION.fast,
                ease: EASING.standard,
              }}
            >
              {highlightSection.label}
            </motion.span>
          </div>,
          document.body,
        )}
    </>
  );
}
```

### `src/components/ui/ScrollSpy/ScrollSpy.module.scss`

Strip the X component from the anchor transform and remove `will-change` (the JS now handles placement; `will-change: top, left` is what caused the GPU promotion that broke `-100%` resolution in the first place):

```scss
// BEFORE
.highlightLabelAnchor {
  position: fixed;
  transform: translate(
    calc(-100% - var(--portfolio-spacer-1x)),
    -50%
  );
  color: #fff;
  mix-blend-mode: difference;
  z-index: var(--portfolio-z-scrollspy);
  pointer-events: none;
  will-change: top, left;
}

// AFTER
.highlightLabelAnchor {
  position: fixed;
  // X offset is fully resolved in JS (notch.left - labelWidth - SPACER_1X).
  // Only Y-centering remains here; -50% of height is always stable because
  // it resolves against the anchor's own line-height box, not against 0.
  // `will-change` removed — it was promoting the layer before text rendered,
  // collapsing the old -100% X to 0 and breaking placement. See FB-156.
  transform: translateY(-50%);
  color: #fff;
  mix-blend-mode: difference;
  z-index: var(--portfolio-z-scrollspy);
  pointer-events: none;
}
```

The full updated SCSS block in context:

```scss
.highlightLabelAnchor {
  position: fixed;
  transform: translateY(-50%);
  color: #fff;
  mix-blend-mode: difference;
  z-index: var(--portfolio-z-scrollspy);
  pointer-events: none;
}

.highlightLabel {
  display: inline-block;
  font-family: var(--portfolio-font-mono);
  font-size: var(--portfolio-type-xs);
  line-height: 1;
  font-weight: 500;
  white-space: nowrap;
  will-change: transform, opacity;

  &[data-depth="1"] {
    font-weight: 400;
  }
}
```

(`will-change: transform, opacity` stays on `.highlightLabel` — that's correct, it's a GPU hint for the framer-motion animation on the span itself, and the span has no CSS percentage transform to corrupt.)

---

### One edge case: first-hover frame

On first hover, `anchorRef.current.offsetWidth` is `0` because the anchor hasn't painted yet. This means `left = notch.left - 0 - 8px = notch.left - 8px` on frame 1, which places the anchor's left edge 8px left of the notch — label appears right of the notch for one frame, then `compute()` re-fires (scroll/resize listeners aren't the trigger though). 

Fix this with a second `useLayoutEffect` that forces a re-compute after the anchor mounts:

```tsx
// Add after the main useIsomorphicLayoutEffect:
useIsomorphicLayoutEffect(() => {
  // Re-run compute once the anchor is mounted and the text has rendered,
  // so anchorRef.current.offsetWidth is non-zero on first hover.
  if (!mounted || !highlightSection || overlayPos === null) return;
  const notch = trackRef.current?.querySelector<HTMLElement>(
    `[data-notch-index="${highlightIndex}"]`,
  );
  if (!notch || !anchorRef.current) return;
  const r = notch.getBoundingClientRect();
  const labelWidth = anchorRef.current.offsetWidth;
  if (labelWidth === 0) return; // not painted yet, skip
  setOverlayPos((prev) => {
    const next = { top: r.top + r.height / 2, left: r.left - labelWidth - SPACER_1X };
    if (prev?.left === next.left && prev?.top === next.top) return prev;
    return next;
  });
}, [mounted, highlightSection, highlightIndex]);
```

Actually, a simpler approach: initialize `overlayPos` as `null` and set `visibility: hidden` when null (already done). On first hover, the anchor renders hidden at `{top:0, left:0}` which paints the text and gives `anchorRef.current.offsetWidth` a real value. The `useLayoutEffect` fires synchronously after that paint and calls `compute()` — but `compute()` is only in the first effect's closure and runs only when `highlightVisible` changes. Since `highlightVisible` went from `false` → `true` once, the effect ran once. 

A cleaner solution: make `compute` a stable callback and call it from a `ResizeObserver` on the anchor itself:

```tsx
// Inside the existing useIsomorphicLayoutEffect, after compute():
const ro = new ResizeObserver(() => compute());
if (anchorRef.current) ro.observe(anchorRef.current);
return () => {
  window.removeEventListener("resize", compute);
  window.removeEventListener("scroll", compute, true);
  ro.disconnect();
};
```

This is the most robust approach — whenever the anchor's own size changes (text content changes, font loads), `compute()` re-fires with the correct `offsetWidth`. Here is the final complete `useIsomorphicLayoutEffect`:

```tsx
useIsomorphicLayoutEffect(() => {
  if (!mounted || !highlightVisible || highlightIndex == null) {
    setOverlayPos(null);
    return;
  }

  const compute = () => {
    const notch = trackRef.current?.querySelector<HTMLElement>(
      `[data-notch-index="${highlightIndex}"]`,
    );
    if (!notch) {
      setOverlayPos(null);
      return;
    }
    const r = notch.getBoundingClientRect();
    const labelWidth = anchorRef.current?.offsetWidth ?? 0;
    setOverlayPos({
      top: r.top + r.height / 2,
      left: r.left - labelWidth - SPACER_1X,
    });
  };

  compute();
  window.addEventListener("resize", compute);
  window.addEventListener("scroll", compute, true);

  // Re-compute when the anchor's rendered width changes (e.g. label text
  // swaps on activeIndex change while already hovered, or on first paint
  // when offsetWidth was 0 at effect-run time).
  const ro = new ResizeObserver(compute);
  if (anchorRef.current) ro.observe(anchorRef.current);

  return () => {
    window.removeEventListener("resize", compute);
    window.removeEventListener("scroll", compute, true);
    ro.disconnect();
  };
}, [mounted, highlightVisible, highlightIndex]);
```

